-- ----------------------------
-- Table structure for token
-- ----------------------------
DROP TABLE IF EXISTS `token`;
CREATE TABLE `token`  (
  `id` bigint NOT NULL,
  `userId` bigint NOT NULL COMMENT '持有者id（目前所在）',
  `type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '代币类型，NFT or SBT',
  `createTime` datetime NOT NULL COMMENT '申请代币时间',
  `include` bigint NULL DEFAULT NULL COMMENT 'NFT属于的SBT id',
  `isRent` int NULL DEFAULT 0 COMMENT '是否为租用，0是否，1是是',
  `ownerId` bigint NULL DEFAULT NULL COMMENT '如果是租用，所有者id（所有者）',
  `dataId` bigint NULL DEFAULT NULL COMMENT '如果是NFT，数据id',
  `detail` varchar(400) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '数据详情',
  `keyword` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '关键词，用,分隔（英文逗号）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `ownerId`(`ownerId` ASC) USING BTREE,
  INDEX `nowOwnerId`(`userId` ASC) USING BTREE,
  INDEX `include`(`include` ASC) USING BTREE,
  INDEX `dataId`(`dataId` ASC) USING BTREE,
  CONSTRAINT `include` FOREIGN KEY (`include`) REFERENCES `token` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `nowOwnerId` FOREIGN KEY (`userId`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `ownerId` FOREIGN KEY (`ownerId`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `token_ibfk_1` FOREIGN KEY (`dataId`) REFERENCES `uploaddata` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of token
-- ----------------------------

-- ----------------------------
-- Table structure for tokenhistory
-- ----------------------------
DROP TABLE IF EXISTS `tokenhistory`;
CREATE TABLE `tokenhistory`  (
  `id` bigint NOT NULL,
  `userId` bigint NOT NULL COMMENT '用户id',
  `isSuccess` int NOT NULL COMMENT '是否操作成功，0是失败，1是成功',
  `time` datetime NOT NULL COMMENT '申请时间',
  `tokenId` bigint NULL DEFAULT NULL COMMENT '代币id',
  `msg` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '失败原因',
  `type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '申请代币类型',
  `isUpdate` int NULL DEFAULT NULL COMMENT '是否更新，0是申请，1是更新',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `tokenhistory_id`(`userId` ASC) USING BTREE,
  INDEX `tokenId`(`tokenId` ASC) USING BTREE,
  CONSTRAINT `tokenhistory_ibfk_1` FOREIGN KEY (`tokenId`) REFERENCES `token` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `tokenhistory_id` FOREIGN KEY (`userId`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of tokenhistory
-- ----------------------------

-- ----------------------------
-- Table structure for trade
-- ----------------------------
DROP TABLE IF EXISTS `trade`;
CREATE TABLE `trade`  (
  `id` bigint NOT NULL,
  `tokenId` bigint NOT NULL COMMENT '出售代币Id',
  `type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '1是出租，0是出售',
  `keyword` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '关键字，以逗号分割',
  `detail` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '具体描述',
  `price` decimal(10, 2) NOT NULL COMMENT '价格，两位小数',
  `time` datetime NOT NULL COMMENT '发出时间',
  `isDone` int NULL DEFAULT 0 COMMENT '是否完成',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '名字',
  `userId` bigint NULL DEFAULT NULL COMMENT '用户id',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `tokenId`(`tokenId` ASC) USING BTREE,
  INDEX `userId`(`userId` ASC) USING BTREE,
  CONSTRAINT `tokenId` FOREIGN KEY (`tokenId`) REFERENCES `token` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `trade_ibfk_1` FOREIGN KEY (`userId`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of trade
-- ----------------------------

-- ----------------------------
-- Table structure for tradehistory
-- ----------------------------
DROP TABLE IF EXISTS `tradehistory`;
CREATE TABLE `tradehistory`  (
  `id` bigint NOT NULL,
  `tradeId` bigint NOT NULL COMMENT '交易id',
  `buyerId` bigint NOT NULL COMMENT '购买者id',
  `time` datetime NOT NULL COMMENT '交易时间',
  `sellerId` bigint NOT NULL COMMENT '出售者id',
  `hash` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `isDelete` int NOT NULL DEFAULT 0 COMMENT '1表示删除',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `tradeId`(`tradeId` ASC) USING BTREE,
  INDEX `buyerId`(`buyerId` ASC) USING BTREE,
  INDEX `sellerId`(`sellerId` ASC) USING BTREE,
  CONSTRAINT `buyerId` FOREIGN KEY (`buyerId`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `tradehistory_ibfk_1` FOREIGN KEY (`sellerId`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `tradeId` FOREIGN KEY (`tradeId`) REFERENCES `trade` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = DYNAMIC;

