-- ----------------------------
-- Table structure for uploaddata
-- ----------------------------
DROP TABLE IF EXISTS `uploaddata`;
CREATE TABLE `uploaddata`  (
  `id` bigint NOT NULL,
  `userId` bigint NOT NULL COMMENT '所有者id',
  `hash` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '上传到ipfs返回的hash值',
  `type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件后缀',
  `keyword` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '数据关键字，逗号分隔',
  `detail` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '数据详细信息',
  `time` datetime NULL DEFAULT NULL COMMENT '最后一次更新时间',
  `isDeleted` int NULL DEFAULT 0 COMMENT '是否被删除',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '数据名称',
  `size` int NULL DEFAULT 200 COMMENT '数据量',
  `dataType` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '数据类型，比如数字、文本、图片',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `data-ownerId`(`userId` ASC) USING BTREE,
  CONSTRAINT `data-ownerId` FOREIGN KEY (`userId`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = DYNAMIC;

