INSERT INTO `bert_detection` VALUES (1, 'contract (1).sol', '\n    // SPDX-License-Identifier: MIT\npragma solidity ^0.8.0;\n\ncontract SignatureVerifier {\n    // 存储签名者地址\n    address private signer;\n\n    // 构造函数设置签名者地址\n    constructor(address _signer) {\n        signer = _signer;\n    }\n\n    // 验证签名\n    function verifySignature(\n        bytes32 messageHash, // 消息哈希\n        bytes memory signature // 签名\n    ) public view returns (bool) {\n        // 通过签名恢复地址\n        address recoveredAddress = recoverSigner(messageHash, signature);\n        return recoveredAddress == signer;\n    }\n\n    // 从签名中恢复签名者地址\n    function recoverSigner(bytes32 messageHash, bytes memory signature) internal pure returns (address) {\n        (bytes32 r, bytes32 s, uint8 v) = splitSignature(signature);\n        return ecrecover(messageHash, v, r, s);\n    }\n\n    // 将签名分割为 r, s, v\n    function splitSignature(bytes memory sig) internal pure returns (bytes32 r, bytes32 s, uint8 v) {\n        require(sig.length == 65, \"Invalid signature length\");\n\n        assembly {\n            // 通过位移将签名拆分成 r, s, v\n            r := mload(add(sig, 32))\n            s := mload(add(sig, 64))\n            v := byte(0, mload(add(sig, 96)))\n        }\n    }\n}\n', '2025-12-02 12:03:45', 0, 0.286629, 0.713371, 0, 0.278331, 0.721669, 0, 0.268971, 0.731029, 0, 0.26904, 0.73096, 0);
