INSERT INTO `bert_detection` VALUES (3, 'test_code.sol', 'contract Etheropt {\r\nstruct Account {\r\nint capital;\r\n}\r\nmapping(uint => Account) accounts;\r\nmapping(address => uint) accountIDs;\r\nfunction withdrawFunds(uint amount) {\r\nif (accountIDs[msg.sender] > 0) {\r\nif (int(amount) > 0) {\r\naccounts[accountIDs[msg.sender]].capital -= int(amount);\r\nmsg.sender.call.value(amount)();\r\n}\r\n}\r\n}\r\n}', '2025-12-13 16:19:17', 0, 0.268956, 0.731044, 1, 0.729765, 0.270235, 0, 0.268949, 0.731051, 1, 0.731013, 0.268987, 1);
INSERT INTO `bert_detection` VALUES (4, '1.sol', '// SPDX-License-Identifier: MIT\r\npragma solidity ^0.4.26;\r\n\r\ncontract TetherUSD {\r\n    string public name = \"Tether USD\";\r\n    string public symbol = \"USDT\";\r\n    uint8 public decimals = 18;\r\n    uint256 public totalSupply;\r\n\r\n    mapping (address => uint256) public balanceOf;\r\n    mapping (address => mapping (address => uint256)) public allowance;\r\n\r\n    event Transfer(address indexed from, address indexed to, uint256 value);\r\n    event Approval(address indexed owner, address indexed spender, uint256 value);\r\n\r\n    constructor(uint256 initialSupply) public {\r\n        totalSupply = initialSupply * 10 ** uint256(decimals);\r\n        balanceOf[msg.sender] = totalSupply;\r\n    }\r\n\r\n    function transfer(address _to, uint256 _value) public returns (bool success) {\r\n        require(_to != address(0), \"Invalid address\");\r\n        require(balanceOf[msg.sender] >= _value, \"Insufficient balance\");\r\n\r\n        balanceOf[msg.sender] -= _value;\r\n        balanceOf[_to] += _value;\r\n\r\n        emit Transfer(msg.sender, _to, _value);\r\n        return true;\r\n    }\r\n\r\n    function approve(address _spender, uint256 _value) public returns (bool success) {\r\n        require(_spender != address(0), \"Invalid address\");\r\n\r\n        allowance[msg.sender][_spender] = _value;\r\n\r\n        emit Approval(msg.sender, _spender, _value);\r\n        return true;\r\n    }\r\n\r\n    function transferFrom(address _from, address _to, uint256 _value) public returns (bool success) {\r\n        require(_to != address(0), \"Invalid address\");\r\n        require(balanceOf[_from] >= _value, \"Insufficient balance\");\r\n        require(allowance[_from][msg.sender] >= _value, \"Allowance exceeded\");\r\n\r\n        balanceOf[_from] -= _value;\r\n        balanceOf[_to] += _value;\r\n        allowance[_from][msg.sender] -= _value;\r\n\r\n        emit Transfer(_from, _to, _value);\r\n        return true;\r\n    }\r\n}\r\n', '2025-12-13 16:39:08', 0, 0.294631, 0.705369, 0, 0.271153, 0.728847, 0, 0.268952, 0.731048, 0, 0.268965, 0.731035, 0);
INSERT INTO `bert_detection` VALUES (5, 'sample9_reen.sol', 'pragma solidity ^0.4.26;\r\n\r\ncontract VictimToken {\r\n    mapping(address => uint) public balances;\r\n    Token public token;\r\n\r\n    constructor(address _tokenAddress) public {\r\n        token = Token(_tokenAddress);\r\n    }\r\n\r\n    function deposit() public payable {\r\n        balances[msg.sender] += msg.value;\r\n    }\r\n    \r\n    function withdraw(uint amount) public {\r\n        require(balances[msg.sender] >= amount);\r\n        token.transfer(msg.sender, amount); \r\n        balances[msg.sender] -= amount;\r\n    }\r\n}\r\n\r\ncontract Token {\r\n    function transfer(address to, uint amount) public returns (bool) {\r\n        return true;\r\n    }\r\n}', '2025-12-17 20:29:26', 0, 0.27282, 0.72718, 0, 0.271421, 0.728579, 0, 0.268948, 0.731052, 1, 0.713253, 0.286747, 1);
INSERT INTO `bert_detection` VALUES (6, 'sample10_overflow.sol', 'pragma solidity ^0.4.26;\r\n\r\ncontract FundIncrement {\r\n    mapping(address => uint) public balances;\r\n    uint public counter = 0;\r\n\r\n    function main() public payable {\r\n        if (counter < 100) {\r\n            msg.sender.send(msg.value + 1);\r\n            counter = counter + 1; // 使用自增运算符\r\n        }\r\n    }\r\n}', '2025-03-05 18:18:19', 1, 0.731015, 0.268985, 1, 0.730933, 0.269067, 0, 0.268949, 0.731051, 0, 0.269255, 0.730745, 1);
INSERT INTO `bert_detection` VALUES (7, 'sample13_overflow.sol', 'pragma solidity ^0.4.26;\r\n\r\ncontract FundRecursive {\r\n    mapping(address => uint) public balances;\r\n    uint public counter = 0;\r\n\r\n    function main(uint depth) public payable {\r\n        if (depth > 0) {\r\n            main(depth - 1); // 递归调用\r\n        }\r\n        if (counter < 100) {\r\n            msg.sender.send(1);\r\n            counter += 1;\r\n        }\r\n    }\r\n}', '2025-03-05 19:27:38', 1, 0.730886, 0.269114, 1, 0.730977, 0.269023, 0, 0.268949, 0.731051, 1, 0.603803, 0.396197, 1);
