INSERT INTO `gpt_detection` VALUES (1, 'contract (1).sol', '\n    // SPDX-License-Identifier: MIT\npragma solidity ^0.8.0;\n\ncontract SignatureVerifier {\n    // 存储签名者地址\n    address private signer;\n\n    // 构造函数设置签名者地址\n    constructor(address _signer) {\n        signer = _signer;\n    }\n\n    // 验证签名\n    function verifySignature(\n        bytes32 messageHash, // 消息哈希\n        bytes memory signature // 签名\n    ) public view returns (bool) {\n        // 通过签名恢复地址\n        address recoveredAddress = recoverSigner(messageHash, signature);\n        return recoveredAddress == signer;\n    }\n\n    // 从签名中恢复签名者地址\n    function recoverSigner(bytes32 messageHash, bytes memory signature) internal pure returns (address) {\n        (bytes32 r, bytes32 s, uint8 v) = splitSignature(signature);\n        return ecrecover(messageHash, v, r, s);\n    }\n\n    // 将签名分割为 r, s, v\n    function splitSignature(bytes memory sig) internal pure returns (bytes32 r, bytes32 s, uint8 v) {\n        require(sig.length == 65, \"Invalid signature length\");\n\n        assembly {\n            // 通过位移将签名拆分成 r, s, v\n            r := mload(add(sig, 32))\n            s := mload(add(sig, 64))\n            v := byte(0, mload(add(sig, 96)))\n        }\n    }\n}\n', '2025-12-02 12:03:57', 1, 0.988913, 0.0110869, 1, 0.856994, 0.143006, 1, 0.807177, 0.192823, 0, 0.0966041, 0.903396, 1);
INSERT INTO `gpt_detection` VALUES (2, '1.sol', 'pragma solidity ^0.4.17;\n\ncontract SimpleContract {\n    uint public myData;\n\n    function setMyData(uint newData) public {\n        myData = newData;\n    }\n}\n', '2025-12-02 12:04:53', 1, 0.893618, 0.106382, 0, 0.000149789, 0.99985, 0, 0.000046531, 0.999954, 0, 0.00254548, 0.997454, 1);
INSERT INTO `gpt_detection` VALUES (3, 'test_code.sol', 'contract Etheropt {\r\nstruct Account {\r\nint capital;\r\n}\r\nmapping(uint => Account) accounts;\r\nmapping(address => uint) accountIDs;\r\nfunction withdrawFunds(uint amount) {\r\nif (accountIDs[msg.sender] > 0) {\r\nif (int(amount) > 0) {\r\naccounts[accountIDs[msg.sender]].capital -= int(amount);\r\nmsg.sender.call.value(amount)();\r\n}\r\n}\r\n}\r\n}', '2025-12-13 16:20:15', 0, 0.0000140896, 0.999986, 1, 0.99491, 0.0050897, 0, 0.0000236421, 0.999976, 1, 0.925792, 0.0742082, 1);
INSERT INTO `gpt_detection` VALUES (4, '1.sol', '// SPDX-License-Identifier: MIT\r\npragma solidity ^0.4.26;\r\n\r\ncontract TetherUSD {\r\n    string public name = \"Tether USD\";\r\n    string public symbol = \"USDT\";\r\n    uint8 public decimals = 18;\r\n    uint256 public totalSupply;\r\n\r\n    mapping (address => uint256) public balanceOf;\r\n    mapping (address => mapping (address => uint256)) public allowance;\r\n\r\n    event Transfer(address indexed from, address indexed to, uint256 value);\r\n    event Approval(address indexed owner, address indexed spender, uint256 value);\r\n\r\n    constructor(uint256 initialSupply) public {\r\n        totalSupply = initialSupply * 10 ** uint256(decimals);\r\n        balanceOf[msg.sender] = totalSupply;\r\n    }\r\n\r\n    function transfer(address _to, uint256 _value) public returns (bool success) {\r\n        require(_to != address(0), \"Invalid address\");\r\n        require(balanceOf[msg.sender] >= _value, \"Insufficient balance\");\r\n\r\n        balanceOf[msg.sender] -= _value;\r\n        balanceOf[_to] += _value;\r\n\r\n        emit Transfer(msg.sender, _to, _value);\r\n        return true;\r\n    }\r\n\r\n    function approve(address _spender, uint256 _value) public returns (bool success) {\r\n        require(_spender != address(0), \"Invalid address\");\r\n\r\n        allowance[msg.sender][_spender] = _value;\r\n\r\n        emit Approval(msg.sender, _spender, _value);\r\n        return true;\r\n    }\r\n\r\n    function transferFrom(address _from, address _to, uint256 _value) public returns (bool success) {\r\n        require(_to != address(0), \"Invalid address\");\r\n        require(balanceOf[_from] >= _value, \"Insufficient balance\");\r\n        require(allowance[_from][msg.sender] >= _value, \"Allowance exceeded\");\r\n\r\n        balanceOf[_from] -= _value;\r\n        balanceOf[_to] += _value;\r\n        allowance[_from][msg.sender] -= _value;\r\n\r\n        emit Transfer(_from, _to, _value);\r\n        return true;\r\n    }\r\n}\r\n', '2025-12-13 16:38:47', 1, 0.893618, 0.106382, 0, 0.000149789, 0.99985, 0, 0.000046531, 0.999954, 0, 0.00254548, 0.997454, 1);
INSERT INTO `gpt_detection` VALUES (5, 'sample13_overflow.sol', 'pragma solidity ^0.4.26;\r\n\r\ncontract FundRecursive {\r\n    mapping(address => uint) public balances;\r\n    uint public counter = 0;\r\n\r\n    function main(uint depth) public payable {\r\n        if (depth > 0) {\r\n            main(depth - 1); // 递归调用\r\n        }\r\n        if (counter < 100) {\r\n            msg.sender.send(1);\r\n            counter += 1;\r\n        }\r\n    }\r\n}', '2025-12-13 21:09:54', 1, 0.990935, 0.0090646, 1, 0.99586, 0.00414021, 0, 0.00698664, 0.993013, 1, 0.993361, 0.00663919, 1);
