INSERT INTO `gpt_detection` VALUES (22, 'contract_10.sol', 'pragma solidity ^0.8.0; abstract contract ReentrancyGuard { uint256 private constant _NOT_ENTERED = 1; uint256 private constant _ENTERED = 2; uint256 private _status; constructor() { _status = _NOT_ENTERED; } modifier nonReentrant() { _nonReentrantBefore(); _; _nonReentrantAfter(); } function _nonReentrantBefore() private { require(_status != _ENTERED, \"ReentrancyGuard: reentrant call\"); _status = _ENTERED; } function _nonReentrantAfter() private { _status = _NOT_ENTERED; } } pragma solidity ^0.8.0; abstract contract Context { function _msgSender() internal view virtual returns (address) { return msg.sender; } function _msgData() internal view virtual returns (bytes calldata) { return msg.data; } } pragma solidity ^0.8.0; abstract contract Ownable is Context { address private _owner; event OwnershipTransferred(address indexed previousOwner, address indexed newOwner); constructor() { _transferOwnership(_msgSender()); } modifier onlyOwner() { _checkOwner(); _; } function owner() public view virtual returns (address) { return _owner; } function _checkOwner() internal view virtual { require(owner() == _msgSender(), \"Ownable: caller is not the owner\"); } function renounceOwnership() public virtual onlyOwner { _transferOwnership(address(0)); } function transferOwnership(address newOwner) public virtual onlyOwner { require(newOwner != address(0), \"Ownable: new owner is the zero address\"); _transferOwnership(newOwner); } function _transferOwnership(address newOwner) internal virtual { address oldOwner = _owner; _owner = newOwner; emit OwnershipTransferred(oldOwner, newOwner); } } pragma solidity >=0.8.17; contract TokenBank is Ownable, ReentrancyGuard { mapping(uint256 => uint256) private _tokenBalance; mapping(uint256 => uint256) private _unlockEpoch; function deposit(uint256 tokenId, uint256 unlockEpoch) payable external onlyOwner nonReentrant { _tokenBalance[tokenId] = msg.value; _unlockEpoch[tokenId] = unlockEpoch; } function withdraw(uint256 tokenId, address owner) external onlyOwner nonReentrant { require(block.timestamp >= _unlockEpoch[tokenId], \"Wait for unlock.\"); payable(owner).transfer(_tokenBalance[tokenId]); _tokenBalance[tokenId] = 0; } function balanceOfToken(uint256 tokenId) external view returns (uint256) { return _tokenBalance[tokenId]; } function getUnlockDate(uint256 tokenId) external view returns (uint256) { return _unlockEpoch[tokenId]; } }', '2025-04-15 20:24:38', 0, 0.00987856, 0.990121, 1, 0.998992, 0.00100849, 0, 0.0000391279, 0.999961, 0, 0.000468425, 0.999532, 1);
INSERT INTO `gpt_detection` VALUES (31, 'deepseekgenerate.sol', '// SPDX-License-Identifier: MIT\npragma solidity ^0.8.0;\n\n/**\n * @title SimpleToken\n * @dev 一个符合ERC20标准的简单代币合约\n */\ncontract SimpleToken {\n    string public name;\n    string public symbol;\n    uint8 public decimals;\n    uint256 public totalSupply;\n    \n    mapping(address => uint256) private _balances;\n    mapping(address => mapping(address => uint256)) private _allowances;\n\n    event Transfer(address indexed from, address indexed to, uint256 value);\n    event Approval(address indexed owner, address indexed spender, uint256 value);\n\n    /**\n     * @dev 构造函数，初始化代币参数\n     * @param _name 代币名称（如\"MyToken\"）\n     * @param _symbol 代币符号（如\"MTK\"）\n     * @param _decimals 代币精度（通常为18）\n     * @param _initialSupply 初始发行量（单位：最小单位，需乘以10^decimals）\n     */\n    constructor(\n        string memory _name,\n        string memory _symbol,\n        uint8 _decimals,\n        uint256 _initialSupply\n    ) {\n        name = _name;\n        symbol = _symbol;\n        decimals = _decimals;\n        totalSupply = _initialSupply * 10 ** decimals;\n        _balances[msg.sender] = totalSupply;\n        emit Transfer(address(0), msg.sender, totalSupply);\n    }\n\n    /**\n     * @dev 查询账户余额\n     */\n    function balanceOf(address account) public view returns (uint256) {\n        return _balances[account];\n    }\n\n    /**\n     * @dev 转账代币\n     * @param to 接收地址\n     * @param value 转账数量（最小单位）\n     */\n    function transfer(address to, uint256 value) public returns (bool) {\n        require(_balances[msg.sender] >= value, \"Insufficient balance\");\n        _balances[msg.sender] -= value;\n        _balances[to] += value;\n        emit Transfer(msg.sender, to, value);\n        return true;\n    }\n\n    /**\n     * @dev 授权额度\n     * @param spender 被授权地址\n     * @param value 授权数量\n     */\n    function approve(address spender, uint256 value) public returns (bool) {\n        _allowances[msg.sender][spender] = value;\n        emit Approval(msg.sender, spender, value);\n        return true;\n    }\n\n    /**\n     * @dev 查询授权额度\n     */\n    function allowance(address owner, address spender) public view returns (uint256) {\n        return _allowances[owner][spender];\n    }\n\n    /**\n     * @dev 从授权地址转账\n     * @param from 资金来源地址\n     * @param to 接收地址\n     * @param value 转账数量\n     */\n    function transferFrom(address from, address to, uint256 value) public returns (bool) {\n        require(_allowances[from][msg.sender] >= value, \"Allowance exceeded\");\n        require(_balances[from] >= value, \"Insufficient balance\");\n        \n        _allowances[from][msg.sender] -= value;\n        _balances[from] -= value;\n        _balances[to] += value;\n        emit Transfer(from, to, value);\n        return true;\n    }\n}', '2025-04-27 16:05:34', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0);
