 value;\n        emit Approval(msg.sender, spender, value);\n        return true;\n    }\n\n    /**\n     * @dev 查询授权额度\n     */\n    function allowance(address owner, address spender) public view returns (uint256) {\n        return _allowances[owner][spender];\n    }\n\n    /**\n     * @dev 从授权地址转账\n     * @param from 资金来源地址\n     * @param to 接收地址\n     * @param value 转账数量\n     */\n    function transferFrom(address from, address to, uint256 value) public returns (bool) {\n        require(_allowances[from][msg.sender] >= value, \"Allowance exceeded\");\n        require(_balances[from] >= value, \"Insufficient balance\");\n        \n        _allowances[from][msg.sender] -= value;\n        _balances[from] -= value;\n        _balances[to] += value;\n        emit Transfer(from, to, value);\n        return true;\n    }\n}', '2025-04-28 18:56:51', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0);
INSERT INTO `gpt_detection` VALUES (54, 'sample11_overflow.sol', 'pragma solidity ^0.4.26;\r\n\r\ncontract FundLoop {\r\n    mapping(address => uint) public balances;\r\n    uint public counter = 0;\r\n\r\n    function main(uint times) public payable {\r\n        for (uint i = 0; i < times; i++) {\r\n            if (counter < 100) {\r\n                msg.sender.send(1);\r\n                counter += 1;\r\n            }\r\n        }\r\n    }\r\n}', '2025-04-30 16:09:02', 1, 0.97755, 0.0224498, 1, 0.998022, 0.0019776, 0, 0.0118038, 0.988196, 1, 0.793419, 0.206581, 1);
