INSERT INTO `token` VALUES (1764985914076221442, 1764630746335907841, 'SBT', '2025-03-05 20:06:48', NULL, 0, NULL, 1764912090995507202, '人工智能是指通过计算机模拟人类智能的技术和系统。它涵盖了机器学习、深度学习、自然语言处理、计算机视觉等领域。人工智能技术已广泛应用于语音识别、图像识别、自动驾驶、智能机器人等领域，为社会带来了巨大的变革。', '人工智能');
INSERT INTO `token` VALUES (1764985969839493121, 1783445843648794626, 'NFT', '2025-03-05 20:07:02', 1764986129034301442, 1, 1783445843648794626, 1765396494813507586, '机器学习是人工智能的一个分支，通过让计算机从数据中学习模式和规律，从而提高其性能和准确性。它在预测、分类、聚类等方面有着广泛的应用。机器学习是人工智能的一个重要分支，它通过训练计算机算法使其具有从数据中学习的能力，而不需要明确编程。机器学习算法可以根据输入数据自动进行模式识别和预测，广泛应用于推荐系统、风险分析、医疗诊断等领域。', '机器学习');
INSERT INTO `token` VALUES (1764985970426695681, 1785557673573941250, 'NFT', '2025-03-05 20:07:02', 1764996027117789186, 1, 1764635912892067842, 1765398447140372482, '深度学习是机器学习的一种特殊形式，它模仿人类大脑的神经网络结构，通过多层次的神经网络进行特征提取和学习。深度学习在图像识别、语音识别、自然语言处理等领域取得了巨大成功，被认为是推动人工智能发展的关键技术之一。', '深度学习');
INSERT INTO `token` VALUES (1764985970946789377, 1783445843648794626, 'NFT', '2025-03-05 20:07:02', 1764995987947184130, 1, 1764635912892067842, 1765605570797486081, '自然语言处理是人工智能领域的一个重要分支，它研究如何使计算机能够理解、分析和生成自然语言文本。NLP技术已被广泛应用于机器翻译、语音识别、文本分类等领域，为人们提供了更智能化的语言交互体验。', '自然语言处理');
INSERT INTO `token` VALUES (1764985971399774209, 1764630746335907841, 'NFT', '2025-03-05 20:07:02', 1764995987947184130, 0, NULL, 1765614138481184770, '计算机视觉是研究如何使计算机能够“看”的技术，它涉及图像处理、模式识别、机器学习等多个领域。计算机视觉技术已被应用于人脸识别、车辆识别、无人驾驶等领域，为社会带来了更安全、便捷的生活方式。', '计算机视觉');
INSERT INTO `token` VALUES (1764985971915673601, 1764630746335907841, 'NFT', '2025-03-05 20:07:02', NULL, 0, NULL, 1785115476307038210, '智能机器人是一种具有人工智能和自主决策能力的机器人系统。它可以通过感知、学习和规划等技术实现自主导航、任务执行等功能，广泛应用于工业生产、服务机器人、医疗护理等领域，为人类提供了更多的帮助和支持。', '智能机器人');
INSERT INTO `token` VALUES (1764985972695814145, 1764630746335907841, 'NFT', '2025-03-05 20:07:02', 1764996125860093954, 0, NULL, 1785563762428280834, '数据科学是一种利用统计学、机器学习、数据分析等技术从数据中提取知识和洞见的跨学科领域。数据科学家通过收集、清洗、分析和可视化数据，发现数据背后的规律和趋势，为企业决策和创新提供支持。', '数据科学');
INSERT INTO `token` VALUES (1764986129034301442, 1764630746335907841, 'SBT', '2025-03-05 20:07:40', NULL, 0, NULL, NULL, '大数据分析是一种利用大规模数据集进行分析和挖掘的技术。它涉及数据收集、存储、处理和分析等多个环节，通过数据挖掘、机器学习等方法发现数据中的模式和关联，为企业决策和市场营销提供指导。', '大数据分析');
INSERT INTO `token` VALUES (1764995987947184130, 1764630746335907841, 'SBT', '2025-03-05 20:46:50', NULL, 0, NULL, NULL, '数据挖掘是一种从大规模数据集中发现隐藏在其中的模式、关联和趋势的过程。数据挖掘技术包括分类、聚类、关联规则挖掘等方法，被广泛应用于市场分析、客户关系管理、欺诈检测等领域。', '数据挖掘');
INSERT INTO `token` VALUES (1764996027117789186, 1764630746335907841, 'SBT', '2025-03-05 20:47:00', NULL, 0, NULL, NULL, '云计算是一种基于互联网的计算模式，通过虚拟化技术将计算资源提供给用户，以服务的形式提供计算能力、存储空间和应用程序等。云计算技术可以提高计算资源的利用率和灵活性，降低IT成本，促进创新和协作。', '云计算');
INSERT INTO `token` VALUES (1764996085401837569, 1764630746335907841, 'SBT', '2025-03-05 20:47:13', NULL, 0, NULL, NULL, '物联网是一种通过互联网连接和通信的技术，使得物体（如传感器、设备、车辆等）能够相互交换数据和信息。物联网技术已被广泛应用于智能家居、智能城市、工业自动化等领域，实现了物与物之间的互联互通，为人们提供了更智能、便捷的生活方式。', '物联网');
INSERT INTO `token` VALUES (1764996125860093954, 1764630746335907841, 'SBT', '2025-03-05 20:47:23', NULL, 0, NULL, NULL, '边缘计算是一种将计算和数据存储功能放置在接近数据源的位置，以减少数据传输延迟和网络带宽消耗的技术。边缘计算可用于智能设备、传感器网络等场景，提高了数据处理的效率和实时性。', '边缘计算');
INSERT INTO `token` VALUES (1765007832795930625, 1785557673573941250, 'NFT', '2025-03-05 21:33:54', 1764996125860093954, 0, NULL, 1785567110053298178, '虚拟现实是一种通过计算机技术模拟出的沉浸式体验，使用户感觉身临其境。虚拟现实技术通常通过头戴式显示器和手持控制器等设备实现，已被广泛应用于游戏、娱乐、教育、医疗等领域。', '虚拟现实');
INSERT INTO `token` VALUES (1765007845924102145, 1785557673573941250, 'NFT', '2025-03-05 21:33:57', 1764985914076221442, 1, 1783445843648794626, 1785567405235830785, '增强现实是一种将虚拟信息叠加到现实世界中的技术，通过摄像头和显示屏等设备实现。增强现实技术可以提供丰富的信息和交互体验，被广泛应用于游戏、导航、维修保养等领域。', '增强现实');
INSERT INTO `token` VALUES (1765007847157227521, 1764630746335907841, 'NFT', '2025-03-05 21:33:58', NULL, 0, NULL, 1785567459489153026, '量子计算是一种利用量子力学原理进行计算的新型计算机技术。量子计算机能够处理复杂的数学和科学问题，具有高速度和高效率的特点，被认为是未来计算机发展的重要方向。', '量子计算');
INSERT INTO `token` VALUES (1765007847740235778, 1785557673573941250, 'NFT', '2025-03-05 21:33:58', 1785679934935072769, 1, 1783445843648794626, 1785567507333578754, '人机交互是研究人类与计算机之间交互和通信的学科。它涵盖了图形用户界面、语音识别、手势识别等技术，旨在提高用户与计算机系统之间的交互效率和用户体验。', '人机交互');
INSERT INTO `token` VALUES (1765007848327438337, 1764630746335907841, 'NFT', '2025-03-05 21:33:58', NULL, 0, NULL, 1785567913702916098, '自动驾驶是一种利用传感器、摄像头、雷达等设备实现车辆无人驾驶的技术。自动驾驶技术可以提高交通安全性、减少交通拥堵，并为乘客提供更便捷的出行体验。', '自动驾驶');
INSERT INTO `token` VALUES (1765007848847532033, 1783445843648794626, 'NFT', '2025-03-05 21:33:58', 1764995987947184130, 0, NULL, 1785567948708577281, '智能家居是一种利用物联网技术实现家居设备自动化控制和远程监控的系统。智能家居可以实现灯光、温度、安全系统等设备的智能化管理，提高家居生活的舒适性和便捷性。', '智能家居');
INSERT INTO `token` VALUES (1765007849308905473, 1764630746335907841, 'NFT', '2025-03-05 21:33:58', NULL, 0, NULL, 1785567993017204738, '智能医疗是利用人工智能、物联网等技术提升医疗服务的效率和质量。智能医疗系统可以实现医疗数据的实时监测、健康管理和远程诊疗，为患者提供更个性化、精准的医疗服务。', '智能医疗');
INSERT INTO `token` VALUES (1765007849766084610, 1764630746335907841, 'NFT', '2025-03-05 21:33:58', 1764996125860093954, 0, NULL, 1785564314558070785, '人工智能伦理是研究人工智能应用中涉及的道德和价值问题的学科。随着人工智能技术的快速发展，涉及隐私、安全、公平、透明等伦理问题变得日益重要。人工智能伦理研究致力于解决这些问题，确保人工智能的发展符合道德和社会价值。', '人工智能伦理');
INSERT INTO `token` VALUES (1765007850344898562, 1764630746335907841, 'NFT', '2025-03-05 21:33:58', NULL, 0, NULL, 1785565444591648769, '人工智能应用是指将人工智能技术应用于各个领域和行业解决实际问题的过程。人工智能应用涵盖了机器学习、深度学习、自然语言处理、计算机视觉等技术，已被广泛应用于语音识别、图像识别、智能推荐系统、智能客服等领域。', '人工智能应用');
INSERT INTO `token` VALUES (1765007850932101121, 1764630746335907841, 'NFT', '2025-03-05 21:33:59', 1785602575930294273, 0, NULL, 1785565679015493633, '区块链技术是一种去中心化的分布式账本技术，通过加密和共识机制确保数据的安全和透明。区块链技术可以实现去中心化的数据存储和交易，被广泛应用于数字货币、智能合约、供应链管理等领域。', '区块链技术');
INSERT INTO `token` VALUES (1765007851963899905, 1764630746335907841, 'NFT', '2025-03-05 21:33:59', 1764995987947184130, 0, NULL, 1785565934045954049, '加密货币是一种基于区块链技术的数字资产，具有去中心化、匿名性和不可篡改等特点。比特币、以太币等是常见的加密货币，它们可以用于价值交换、投资、支付等目的，已成为数字经济的重要组成部分。', '加密货币');
INSERT INTO `token` VALUES (1765007852421079041, 1764630746335907841, 'NFT', '2025-03-05 21:33:59', 1785602575930294273, 0, NULL, 1785566640794566658, '智能合约是一种基于区块链技术的自动化合约，通过编程代码实现合约条款的自动执行。智能合约可以实现去中心化的交易和资产转移，被广泛应用于数字货币交易、供应链管理、金融衍生品等领域。', '智能合约');
INSERT INTO `token` VALUES (1783810829139054593, 1783445843648794626, 'NFT', '2025-04-26 18:50:18', 1785602575930294273, 0, NULL, NULL, '去中心化是一种不依赖于单一中心控制的组织或系统结构。区块链技术的核心特点之一就是去中心化，它可以实现数据和权力的分散存储和管理，提高系统的安全性和透明度。', '去中心化');
INSERT INTO `token` VALUES (1783810850962018305, 1783445843648794626, 'NFT', '2025-04-26 18:50:23', 1785602575930294273, 0, NULL, NULL, '分布式账本技术是一种去中心化的数据存储和交易技术，通过多个节点共同维护数据的一致性和安全性。区块链是分布式账本技术的一种实现方式，但并非唯一。分布式账本技术可以应用于金融、供应链管理、数字身份验证等领域。', '分布式账本技术');
INSERT INTO `token` VALUES (1783810852845260801, 1783445843648794626, 'NFT', '2025-04-26 18:50:24', NULL, 0, NULL, 1765614138481184770, '数字身份是指个人或实体在网络世界中的唯一标识。传统的身份认证方式存在安全性和便捷性不足的问题，数字身份技术通过加密和身份验证技术实现安全可靠的身份认证，被广泛应用于金融、电子商务等领域。', '数字身份');
INSERT INTO `token` VALUES (1783810853537320961, 1783445843648794626, 'NFT', '2025-04-26 18:50:24', 1764996085401837569, 0, NULL, NULL, '供应链管理是指对产品从生产到销售的全过程进行规划、执行和控制的过程。区块链技术可以提高供应链管理的透明度和可追溯性，减少信息不对称和诚信问题，提高供应链效率和安全性。', '供应链管理');
INSERT INTO `token` VALUES (1783810854174855170, 1785557673573941250, 'NFT', '2025-04-26 18:50:24', NULL, 1, 1783445843648794626, 1785567948708577281, '数据隐私保护是指保护个人数据不被未经授权的访问、使用或泄露的措施。随着数据的数字化和共享，数据隐私保护变得越来越重要。区块链技术可以实现数据的加密存储和访问控制，提高数据的安全性和隐私保护水平。', '数据隐私保护');
INSERT INTO `token` VALUES (1783810854728503297, 1783445843648794626, 'NFT', '2025-04-26 18:50:24', 1783842564857970689, 0, NULL, NULL, '区块链游戏是利用区块链技术实现的游戏平台，具有去中心化、透明、可追溯等特点。区块链游戏通常采用加密货币作为游戏内货币，实现游戏资产的真实拥有权和交易。区块链游戏为玩家提供了更多的自主权和游戏体验。', '区块链游戏');
INSERT INTO `token` VALUES (1783810855236014081, 1783445843648794626, 'NFT', '2025-04-26 18:50:24', 1783811313409200130, 0, NULL, NULL, '区块链金融是指利用区块链技术改变传统金融行业的运作模式。通过区块链技术，金融交易可以实现去中心化、实时结算、低成本等特点，例如数字货币交易、智能合约贷款、去中心化交易所等。', '区块链金融');
INSERT INTO `token` VALUES (1783810855781273601, 1785557673573941250, 'NFT', '2025-04-26 18:50:24', NULL, 1, 1783445843648794626, 1785567913702916098, '区块链投资是指利用区块链技术进行投资的行为。区块链技术可以提高投资的透明度和流动性，降低交易成本和风险，例如数字资产投资、初级代币发行（ICO）、去中心化金融产品等。', '区块链投资');
INSERT INTO `token` VALUES (1783810856766935042, 1783445843648794626, 'NFT', '2025-04-26 18:50:25', 1783811313409200130, 0, NULL, NULL, '区块链认证是指利用区块链技术确保数据和信息的真实性和完整性的过程。区块链技术可以提供不可篡改的数据记录和分布式的信任机制，用于身份认证、文件签名、电子证据等场景。', '区块链认证');
INSERT INTO `token` VALUES (1783810857391886338, 1783445843648794626, 'NFT', '2025-04-26 18:50:25', 1783838757998665729, 0, NULL, 1785567110053298178, '智能合约市场是指基于区块链技术建立的合约交易平台，可以让用户发布、购买和执行智能合约。智能合约市场提供了一个去中心化的交易场所，为智能合约的开发和应用提供了便利。', '智能合约市场');
INSERT INTO `token` VALUES (1783810857953923073, 1783445843648794626, 'NFT', '2025-04-26 18:50:25', 1783811313409200130, 0, NULL, NULL, '区块链供应链是指利用区块链技术改进供应链管理和物流的方式。区块链技术可以提高供应链的透明度、可追溯性和安全性，减少信息不对称和风险，例如产品溯源、货物跟踪、供应链金融等。', '区块链供应链');
INSERT INTO `token` VALUES (1783810858574680066, 1783445843648794626, 'NFT', '2025-04-26 18:50:25', 1785906229174403073, 0, NULL, NULL, '区块链数字资产是指基于区块链技术发行和流通的数字化资产。这些数字资产可以是加密货币、代币、数字证券等，具有去中心化、可编程、不可篡改等特点，被广泛应用于数字资产交易、投资、融资等领域。', '区块链数字资产');
INSERT INTO `token` VALUES (1783810859132522498, 1783445843648794626, 'NFT', '2025-04-26 18:50:25', 1783811313409200130, 0, NULL, NULL, '区块链数字版权是指利用区块链技术保护数字内容的版权和知识产权。区块链技术可以确保数字内容的真实性和完整性，实现版权登记、授权管理、版权交易等功能，保护创作者的合法权益。', '区块链数字版权');
INSERT INTO `token` VALUES (1783810859694559234, 1783445843648794626, 'NFT', '2025-04-26 18:50:25', 1783838757998665729, 0, NULL, 1785565444591648769, '区块链社交网络是指利用区块链技术构建的去中心化社交平台。区块链社交网络通常具有用户数据的去中心化存储、隐私保护、用户激励机制等特点，为用户提供安全、透明的社交环境。', '区块链社交网络');
INSERT INTO `token` VALUES (1783810860256595969, 1783445843648794626, 'NFT', '2025-04-26 18:50:25', 1783811313409200130, 0, NULL, NULL, '区块链物联网是指将物联网设备与区块链技术相结合，实现设备之间的信任和安全交互。区块链技术可以提供可信的数据记录和安全的数据传输，用于物联网设备的身份认证、数据交换、远程控制等应用。', '区块链物联网');
INSERT INTO `token` VALUES (1783810860818632705, 1783445843648794626, 'NFT', '2025-04-26 18:50:25', 1783838849413521410, 0, NULL, NULL, '区块链数字身份是指利用区块链技术确保个人和实体在网络中的唯一标识和身份。区块链数字身份具有去中心化、安全可信、用户控制等特点，可以应用于身份认证、数字身份管理、访问控制等场景。', '区块链数字身份');
INSERT INTO `token` VALUES (1783811313409200130, 1783445843648794626, 'SBT', '2025-04-26 18:52:13', NULL, 0, NULL, NULL, '区块链安全是指保护区块链系统和数据免受攻击和欺诈的技术和策略。区块链安全涉及密码学、共识机制、访问控制、智能合约审计等方面，用于确保区块链网络的完整性、可用性和保密性。', '区块链安全');
INSERT INTO `token` VALUES (1783838757998665729, 1783445843648794626, 'NFT', '2025-04-26 20:41:17', 1764986129034301442, 0, NULL, NULL, '分布式应用程序是一种基于区块链技术构建的去中心化应用程序。与传统的中心化应用程序不同，分布式应用程序通过区块链网络上的多个节点进行数据存储和处理，具有更高的安全性和可靠性。', '分布式应用程序');
INSERT INTO `token` VALUES (1783838849413521410, 1783445843648794626, 'SBT', '2025-04-26 20:41:38', NULL, 0, NULL, NULL, '去中心化金融是指利用区块链技术实现的去中心化金融服务和产品。去中心化金融包括借贷、交易、投资、衍生品等金融活动，通过智能合约和去中心化交易所等工具实现，提供更开放、透明、高效的金融服务。', '去中心化金融');
INSERT INTO `token` VALUES (1783842564857970689, 1783445843648794626, 'SBT', '2025-04-26 20:56:24', NULL, 0, NULL, NULL, '去中心化交易所是一种基于区块链技术构建的去中心化数字资产交易平台。与中心化交易所不同，去中心化交易所不依赖于中心化的交易所运营商，而是通过智能合约实现资产交换，提高了交易的安全性和透明度。', '去中心化交易所');
INSERT INTO `token` VALUES (1783846826019180546, 1783445843648794626, 'NFT', '2025-04-26 21:13:20', 1785727800240046081, 0, NULL, NULL, '区块链智能城市是指利用区块链技术实现城市基础设施和公共服务的智能化管理和运营。区块链智能城市涵盖了城市规划、交通管理、能源管理、环境保护等方面，通过数据共享和智能合约优化城市运行效率和市民生活品质。', '区块链智能城市');
INSERT INTO `token` VALUES (1783846826887401473, 1783445843648794626, 'NFT', '2025-04-26 21:13:20', 1785911166147035138, 0, NULL, NULL, '区块链医疗保健是指利用区块链技术改进医疗信息管理和健康数据交换的方式。区块链医疗保健可以实现医疗数据的安全存储、医疗记录的共享和追溯、患者权益的保护等目标，促进医疗保健行业的数字化转型。', '区块链医疗保健');
INSERT INTO `token` VALUES (1783846827470409731, 1783445843648794626, 'NFT', '2025-04-26 21:13:21', 1785727800240046081, 0, NULL, NULL, '区块链能源管理是指利用区块链技术优化能源生产、分配和消费的过程。区块链能源管理可以实现能源数据的实时监测、能源交易的去中心化和可追溯，促进能源供应链的协同和高效运作。', '区块链能源管理');
INSERT INTO `token` VALUES (1783846828279910401, 1783445843648794626, 'NFT', '2025-04-26 21:13:21', 1785905833936748545, 0, NULL, NULL, '区块链供应链金融是指利用区块链技术优化供应链金融服务和产品。区块链供应链金融可以实现供应链中的资金流动、风险管理和资产流通的数字化和自动化，提高供应链的融资效率和风险控制能力。', '区块链供应链金融');
INSERT INTO `token` VALUES (1785568613753225217, 1783445843648794626, 'NFT', '2025-05-01 15:15:06', 1785727800240046081, 0, NULL, 1785115476307038210, '区块链数字化身份验证是指利用区块链技术实现个人身份信息的安全和可信验证。区块链数字化身份验证可以防止身份盗窃和数据泄露，提高身份认证的安全性和便捷性，被广泛应用于金融、电子商务等领域。', '区块链数字化身份验证');
INSERT INTO `token` VALUES (1785568613778391042, 1783445843648794626, 'NFT', '2025-05-01 15:15:06', 1785602575930294273, 0, NULL, 1785564314558070785, '智能合约审计是指对智能合约代码进行安全性和正确性的审核和检查。由于智能合约执行的不可逆性和公开性，一旦存在漏洞或错误可能导致严重后果。智能合约审计通过对代码逻辑、安全漏洞和潜在风险的审查，确保合约的稳健性和安全性。', '智能合约审计');
INSERT INTO `token` VALUES (1785568613778391043, 1783445843648794626, 'NFT', '2025-05-01 15:15:06', 1785729039812067329, 0, NULL, 1785565934045954049, '区块链教育是指提供关于区块链技术和应用的教育培训服务。随着区块链技术的发展，越来越多的机构和学校开设区块链相关课程和培训，涵盖了区块链基础知识、开发技能、应用场景等内容，培养了一批区块链人才。', '区块链教育');
INSERT INTO `token` VALUES (1785571312414556162, 1785557673573941250, 'NFT', '2025-05-01 15:25:50', 1785728901022547969, 0, NULL, 1785565679015493633, '区块链政府服务是指政府部门利用区块链技术提供的服务和解决方案。区块链政府服务可以应用于身份认证、数据管理、投票选举、供应链监管等领域，提高政府服务的透明度、可信度和效率。', '区块链政府服务');
INSERT INTO `token` VALUES (1785571480115412993, 1785557673573941250, 'NFT', '2025-05-01 15:26:30', 1785729039812067329, 0, NULL, 1785565444591648769, '区块链公益慈善是指利用区块链技术推动公益事业的发展和管理。区块链公益慈善可以实现公益项目的透明筹款、捐赠追踪、资金分配等功能，提高慈善活动的透明度和信任度，促进社会公益事业的发展。', '区块链公益慈善');
INSERT INTO `token` VALUES (1785571603738329089, 1764630746335907841, 'NFT', '2025-05-01 15:26:59', NULL, 0, NULL, NULL, '区块链数字选举是指利用区块链技术实现的公开、安全和透明的选举系统。区块链数字选举可以防止选举舞弊、确保选举结果的可信度，促进民主政治的发展和参与度。', '区块链数字选举');
