INSERT INTO `uploaddata` VALUES (1764912090995507202, 1764630746335907841, '155821276', '', '人工智能,数据挖掘', '这一数据集包含了全国范围内的人工智能应用案例和相关数据，涵盖了各种行业和领域的人工智能应用情况。数据包括了人工智能算法使用情况、应用场景、效果评估等详细信息，适用于研究人工智能技术发展趋势、行业应用情况以及人工智能对经济社会的影响等方面的分析研究。', '2025-03-05 15:14:14', 0, '全国人工智能应用数据', 150, NULL);
INSERT INTO `uploaddata` VALUES (1765396494813507586, 1764630746335907841, '155821276', '', '人工智能,数据挖掘', '这一数据集收集了全国各地的数据挖掘案例和相关数据，包括了不同行业和领域的数据挖掘应用案例、数据来源、挖掘算法、挖掘结果等信息。数据集可以用于研究数据挖掘在各个行业中的应用情况、挖掘模式和效果评估，为数据挖掘研究和应用提供实证支持和参考。', '2025-03-06 23:18:18', 0, '全国数据挖掘案例数据', 0, NULL);
INSERT INTO `uploaddata` VALUES (1765398447140372482, 1764630746335907841, 'QmaFjMNF8TxCdttcWwGF1mEDN899BV3KXZC4t5G7RkktzX', '.csv', '人工智能,数据挖掘', '这一数据集收集了全国各地的数据挖掘案例和相关数据，包括了不同行业和领域的数据挖掘应用案例、数据来源、挖掘算法、挖掘结果等信息。数据集可以用于研究数据挖掘在各个行业中的应用情况、挖掘模式和效果评估，为数据挖掘研究和应用提供实证支持和参考。', '2025-03-06 23:26:04', 0, '全国人口数据', 200, '数字');
INSERT INTO `uploaddata` VALUES (1765605570797486081, 1764630746335907841, 'QmWhdzhiEjcuNAxrsVeb8nvwitcXvi6t41YVtgwgN1cNH5', '', '人工智能,数据挖掘', '这一数据集包含了全国各地的群智感知信息，涵盖了用户提交的各种感知数据，如交通拥堵情况、天气状况、环境污染等，为城市管理和公共决策提供重要参考。', '2025-03-07 13:09:06', 0, '群智感知数据', 100, NULL);
INSERT INTO `uploaddata` VALUES (1765614138481184770, 1764630746335907841, 'QmUpLdaCCKBrJTxsWckcMET4VLbWn3Yno1Xw3hLhiGMRkb', '.png', '人工智能,数据挖掘', '该数据集记录了淘宝平台上用户的行为数据，包括浏览、搜索、购买等行为，用于分析用户偏好、行为路径和购物习惯，为电商运营和精准营销提供支持。', '2025-03-07 13:43:09', 0, '淘宝数据', 0, NULL);
INSERT INTO `uploaddata` VALUES (1785115476307038210, 1783445843648794626, 'QmcwPQzzTNkNQRZ3jN3TJ4hZxsKnEVkTRbzBgm1Ufdq1hX', '.sol', '智能合约', '这一数据集包含了全国范围内的智能合约交易数据，涵盖了不同区块链平台上的智能合约交易记录、合约类型、执行情况等详细信息。数据集适用于研究智能合约的应用场景、交易模式和安全性评估，为区块链技术和智能合约应用提供数据支撑和分析依据。', '2025-04-30 09:14:30', 0, '全国智能合约交易数据', 200, '数字');
INSERT INTO `uploaddata` VALUES (1785563762428280834, 1785557673573941250, 'QmT2Sg5k8EPV2VdRdmKfjqyW3gBmgBujQAAWLmdEggCC4S', '.webp', '数据可视化', '这一数据集收集了全国各个领域的数据可视化应用案例和相关数据，包括了不同行业的数据可视化需求、应用场景、可视化效果等信息。数据集可以用于研究数据可视化技术在不同领域的应用情况、可视化模式和用户体验评价，为数据可视化技术发展和应用提供参考和借鉴。', '2025-05-01 14:55:50', 0, '全国数据可视化应用数据', 200, '图片');
INSERT INTO `uploaddata` VALUES (1785564314558070785, 1783445843648794626, 'QmeXhQyTCZME41G7HKPN5zQ3KuXoesNF1q2SdpNKZH4uDa', '.pdf', '人工智能', '这一数据集收集了社交媒体平台上用户的情绪表达数据，包括文本内容、情感极性等信息，用于分析社会舆情、用户情绪波动和热点话题，为舆情监测和危机管理提供参考。', '2025-05-01 14:58:01', 0, '社交媒体情绪数据', 20, '数字');
INSERT INTO `uploaddata` VALUES (1785565444591648769, 1785557673573941250, 'QmPj545hC7y28ZN4rCwnaAcNpLUDBjNyn8TcgucFtfwfWQ', '.sol', '智能合约', '该数据集包含了医疗健康领域的各种数据，如医院就诊记录、疾病诊断信息、药品使用情况等，用于医疗资源调配、疾病预测和健康管理。', '2025-05-01 15:02:31', 0, '医疗健康数据', 40, '数字');
INSERT INTO `uploaddata` VALUES (1785565679015493633, 1785557673573941250, 'QmR3z13nnfFa7cXT6qwnsPCfDFRnD2sCcgb6FzWm28UwvL', '.jpg', '风景照', '这一数据集记录了城市交通系统的运行数据，包括道路流量、车辆速度、交通事故等信息，用于优化交通管理、缓解交通拥堵和提升交通安全。', '2025-05-01 15:03:27', 0, '智能交通数据', 757, '图片');
INSERT INTO `uploaddata` VALUES (1785565934045954049, 1783445843648794626, 'QmUdzLrHUXVNwJy4iZqg5SZ8vfvuFB1MrE5oV5yNjqKwaP', '.doc', '数据科学', '该数据集包含了金融市场的各种数据，如股票交易数据、债券市场数据、汇率数据等，用于金融风险评估、投资决策和市场预测。', '2025-05-01 15:04:28', 0, '金融市场数据', 57, '数字');
INSERT INTO `uploaddata` VALUES (1785566640794566658, 1783445843648794626, 'QmaBuXuYQULyRrjq6TYLNeC8h9fn4HAWgYtnkNrzWzxoHQ', '.sol', '云计算', '这一数据集收集了气象环境监测数据，包括气温、湿度、风速、空气质量等信息，用于气象预报、环境保护和应急响应。', '2025-05-01 15:07:16', 0, '气象环境数据', 7, '数字');
INSERT INTO `uploaddata` VALUES (1785567110053298178, 1783445843648794626, 'QmUzVAriKFBBtzRd12KTkVtQi7RGERXepdFqz6KKFpkizw', '.txt', '物联网', '该数据集包含了农业生产过程中的各种数据，如种植作物信息、气候条件、土壤质量等，用于农业生产管理、精准农业和农产品质量控制。', '2025-05-01 15:09:08', 0, '农业生产数据', 57, '文本');
