INSERT INTO `uploaddata` VALUES (1785608220008054785, 1783445843648794626, 'QmQAjcDDePnvGGSbSG5Z9r3gBnmqQJEvo4bVsdmrbPAb7b', '.dll', '高效,可信', '该数据集包含了电子商务平台上用户对商品的评论和评价数据，包括评分、文字评论、购买体验等信息，用于产品质量评估、用户口碑分析和品牌声誉管理。通过分析这些数据，商家可以了解用户对产品的真实反馈和需求，改进产品设计和服务质量，提升用户满意度和购物体验。', '2025-05-01 17:52:29', 0, '电子商务用户评论数据', 89, '数字');
INSERT INTO `uploaddata` VALUES (1785608239616425986, 1783445843648794626, 'Qma2KxWo5wpinCGQKY4Tk6wf5fDtgPY6w2XtYwkQYHRVD8', '.dll', '人工智能,大数据', '这一数据集记录了城市轨道交通系统的运行数据，包括列车运行时刻表、客流量统计、车站设施状况等信息，用于城市轨道交通运营管理和乘客服务优化。这些数据可以帮助交通管理部门监控轨道交通系统的运行情况，调整运行计划和车站布局，提高乘客出行的便利性和舒适度。', '2025-05-01 17:52:34', 0, '轨道交通数据', 65, '数字');
INSERT INTO `uploaddata` VALUES (1785881970733547521, 1783445843648794626, 'QmUGzQKqmd4Tm1Cpgn29DazK5J8Xi8zwhCG9pxg2cqxS9K', '.jpg', '数据分析,可视化', '该数据集包含了社会保障制度的相关数据，包括养老保险、医疗保险、失业保险等社会保障项目的参保人数、缴费情况、福利待遇等信息，用于社会保障政策的制定和实施。这些数据可以帮助政府部门了解社会保障制度的运行状况，优化社会保障政策，保障人民群众的基本生活需求和权益。', '2025-05-02 12:00:17', 0, '社会保障数据', 56, '数字');
INSERT INTO `uploaddata` VALUES (1785882046461706242, 1783445843648794626, 'QmZpxPJFX5qvBYxzGi1QAmSZMfWUqqTJfPsydyPxe5BEhD', '.jpg', '大语言模型LLM', '这一数据集包含了医药产品的销售数据，包括药品销售额、销量排名、药品种类等信息，用于医药企业的市场分析、产品定位和营销策略制定。这些数据可以帮助医药企业了解市场需求和竞争态势，优化产品结构和销售渠道，提高市场竞争力和盈利能力。', '2025-05-02 12:00:35', 0, '医药销售数据', 56, '数字');
INSERT INTO `uploaddata` VALUES (1785882146038677505, 1783445843648794626, 'QmbG5uQBQX18DWjZXMRqbnAYfZhtDFWCg9F22gNSwiJMAk', '.jpg', '量子计算机', '这一数据集包含了金融市场的交易数据，包括股票、债券、期货等各类金融资产的交易价格、成交量、交易时段等信息，用于金融市场的交易分析、投资决策和风险管理。这些数据可以帮助投资者了解市场行情和资产价格波动情况，指导投资组合的配置和交易策略的制定，降低投资风险，获取收益。', '2025-05-02 12:00:58', 0, '金融市场数据', 56, '数字');
INSERT INTO `uploaddata` VALUES (1785882237738745858, 1783445843648794626, 'Qme36f7xKjjUkD1Q36FpkG5Bjz3TgEKUxiRhQvrcdnqhYB', '.jpg', '医疗科技', '该数据集记录了城市交通系统的运行数据，包括道路拥堵情况、交通事故统计、公共交通运行情况等信息，用于交通管理部门的交通规划和运营优化。这些数据可以帮助交通管理部门监控交通流量和路况变化，调整交通信号灯配时和公交线路规划，提高城市交通的效率和安全性。', '2025-05-02 12:01:20', 0, '智能交通数据', 23, '数字');
INSERT INTO `uploaddata` VALUES (1785882323159941121, 1783445843648794626, 'QmYdybLprLr9wXew7VVfCns2YKEAbHCnC2bjXhgdRHbzZz', '.jpg', '虚拟助手', '这一数据集包含了供应链上游和下游企业的相关数据，包括原材料采购、生产加工、物流配送、零售销售等环节的信息，用于供应链管理和供应链优化。这些数据可以帮助企业了解供应链各环节的运行状况和效率，优化供应链布局和管理流程，降低成本，提高供应链整体运作效率和灵活性。', '2025-05-02 12:01:41', 0, '供应链数据', 23, '数字');
INSERT INTO `uploaddata` VALUES (1785882427463892993, 1783445843648794626, 'QmYa2EriQksSGXoSqbEtPb98pA9E8am8WZd4aegx3BFYUw', '.jpg', '自动化技术', '该数据集包含了健康保险产品的销售情况、保单签约情况、理赔记录等信息，用于保险公司的产品设计和风险评估。这些数据可以帮助保险公司了解健康保险市场的需求和竞争情况，优化保险产品设计和定价策略，提高保险产品的市场竞争力和盈利能力。', '2025-05-02 12:02:05', 0, '健康保险数据', 36, '数字');
INSERT INTO `uploaddata` VALUES (1785903682917302273, 1783445843648794626, 'QmYHdd4Q4yTv2PKVngxz6azojJY8s6yiYhY1FBr7jG75tM', '.docx', '身份验证', '这一数据集记录了农业生产和农产品销售的相关数据，包括农作物种植面积、产量统计、农产品价格、销售渠道等信息，用于农业生产的规划和市场营销。这些数据可以帮助农民和农业企业了解农业生产和市场供需情况，指导农业生产和经营决策，提高农产品的质量和竞争力。', '2025-05-02 13:26:33', 0, '农业产销数据', 46, '数字');
INSERT INTO `uploaddata` VALUES (1785903728496803842, 1783445843648794626, 'QmcDF1apF5EaitVXaGwn1u1UHdw75ihmrUTeczA1m5zJyv', '.docx', '智能医疗', '该数据集包含了环境监测站点的监测数据，包括空气质量、水质监测、土壤污染等环境指标数据，用于环境保护和生态治理。这些数据可以帮助环保部门监测环境污染情况和生态系统健康状况，制定环保政策和污染治理措施，保护环境和人民健康。', '2025-05-02 13:26:44', 0, '环境监测数据', 6, '数字');
