INSERT INTO `uploaddata` VALUES (1785939099213430786, 1783445843648794626, 'QmXGwRNemfUr8GbbKteN1xNgV3Ay6kAqmcmTDF8qtscPxt', '.png', '智能合约', '该数据集包含了科研项目的申请、资助、成果等相关信息，用于科研资源管理和科研成果评价。这些数据可以帮助科研机构了解科研项目的申请情况和研究方向，优化科研资源配置，促进科技创新和知识产出。', '2025-05-02 15:47:17', 0, '科研项目数据', 56, '数字');
INSERT INTO `uploaddata` VALUES (1785939136060391425, 1783445843648794626, 'QmcxgnaeXNsZdft6WxCCUb7PaGqnitK4fTXDPi13u6MKPE', '.png', '人工智能,大数据', '这一数据集记录了各地旅游景点的游客数量、景点特色、景区服务等信息，用于旅游资源规划和旅游业发展。这些数据可以帮助旅游管理部门了解各景点的游客流量和满意度，制定旅游发展战略和促销策略，推动旅游业的持续健康发展。', '2025-05-02 15:47:26', 0, '旅游景点数据', 896, '数字');
INSERT INTO `uploaddata` VALUES (1785939226225344514, 1783445843648794626, 'QmbUbrBCgAqzrL15ZLyTWhMMTk4Wd3sPAyzabiGhNJUXkG', '.png', '智能合约', '该数据集包含了气象观测站点的气温、湿度、风速等气象参数的监测数据，用于天气预报、气候变化研究和灾害预警。这些数据可以帮助气象部门监测天气变化和气候趋势，提高天气预报的准确性和及时性，保障社会公众的生命财产安全。', '2025-05-02 15:47:47', 0, '气象观测数据', 464, '数字');
INSERT INTO `uploaddata` VALUES (1785939267195305986, 1783445843648794626, 'QmQcP4LnVDn1mJeadgb6RCKHVwNhdLCWLfLuLUt2vJGR5a', '.js', '智能合约', '该数据集包含了网络设备的日志记录信息，包括网络流量、攻击事件、异常行为等，用于网络安全监测和威胁识别。这些数据可以帮助企业和组织及时发现和应对网络安全威胁，保护信息系统的安全和稳定运行。', '2025-05-02 15:47:57', 0, '网络安全日志数据', 465, '数字');
INSERT INTO `uploaddata` VALUES (1785939309142540290, 1783445843648794626, 'QmQDiCXqvPojgyz22g9Zi9CSbAeDj1zzf9ZdAZDQhmJDta', '.jpeg', '量子计算机', '这一数据集记录了航空公司航班的起降时间、航线、机型、乘客数量等信息，用于航空运输管理和航班调度。这些数据可以帮助航空公司优化航班计划和资源配置，提高航班的准点率和服务质量，满足乘客出行需求。', '2025-05-02 15:48:07', 0, '航空运输数据', 536, '数字');
INSERT INTO `uploaddata` VALUES (1785939394861531137, 1783445843648794626, 'Qmf5boK4we13JuuzDeYMFPe6iygZqzfBM1mjy9XSndNrZv', '.png', '智能合约', '该数据集包含了物流公司的配送路线、运输车辆、货物数量等信息，用于物流配送管理和货物跟踪。这些数据可以帮助物流公司优化配送路线和运输计划，提高货物的送达速度和配送效率，满足客户的物流需求。', '2025-05-02 15:48:28', 0, '物流配送数据', 864, '数字');
INSERT INTO `uploaddata` VALUES (1785939447072227330, 1783445843648794626, 'QmZhA8g6YqsPBFjMmDJFKwiehqEzd6iYBTyWWSpUbGCVGb', '.cpp', '医疗科技', '这一数据集记录了农业生产和农产品销售的相关数据，包括农作物种植面积、产量统计、农产品价格、销售渠道等信息，用于农业生产的规划和市场营销。这些数据可以帮助农民和农业企业了解农业生产和市场供需情况，指导农业生产和经营决策，提高农产品的质量和竞争力。', '2025-05-02 15:48:40', 0, '农业产销数据', 35, '数字');
INSERT INTO `uploaddata` VALUES (1785939479427088385, 1783445843648794626, 'QmRvNQ61Xi198VH9fSWzjsRfVeEK1QBBHF9R9ViUAxw8WK', '.ttf', '身份验证', '这一数据集记录了社会保障制度的实施情况，包括养老保险、医疗保险、失业保险等社会保障项目的覆盖范围、参保人数、福利待遇等信息，用于社会保障政策的制定和实施效果评估。这些数据可以帮助政府部门了解社会保障制度的运行情况和参保群体的基本需求，优化社会保障政策，保障人民群众的基本生活和权益。', '2025-05-02 15:48:48', 0, '社会保障数据', 5, '数字');
